from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/')
def home():
    return 'Welcome to PyMasters!'

@app.route('/hello/<name>')
def hello(name):
    return f'Hello, {name}! Welcome to Flask.'

@app.route('/square/<int:num>')
def square(num):
    return jsonify({'number': num, 'square': num ** 2})

if __name__ == '__main__':
    app.run(debug=True)
